class GameView extends View {
    private static final int GRID_SIZE = 9;
    private static final int ELEMENT_SIZE = 100;
    private static final int MARGIN = 10;
    private static final int MAX_STEPS = 20;
    private static final int INITIAL_TARGET_SCORE = 100;
    private int[][] grid;
    private int currentSteps;
    private int currentScore;
    private int targetScore;
    private boolean isGameOver;
    private boolean isDragging;
    private int startX, startY;
    private int endX, endY;
    private Random random;
    private Paint paint;

    public GameView(Context context) {
        super(context);
        init();
    }

    private void init() {
        grid = new int[GRID_SIZE][GRID_SIZE];
        random = new Random();
        paint = new Paint();
        paint.setAntiAlias(true);
        currentSteps = 0;
        currentScore = 0;
        targetScore = INITIAL_TARGET_SCORE;
        isGameOver = false;
        isDragging = false;
        fillGrid();
    }

    private void fillGrid() {
        for (int i = 0; i < GRID_SIZE; i++) {
            for (int j = 0; j < GRID_SIZE; j++) {
                grid[i][j] = random.nextInt(5); // 5 种魔法元素
            }
        }
        checkAndRemoveMatches();
    }

    private void checkAndRemoveMatches() {
        boolean hasMatches = true;
        while (hasMatches) {
            hasMatches = false;
            boolean[][] toRemove = new boolean[GRID_SIZE][GRID_SIZE];

            // 检查水平匹配
            for (int i = 0; i < GRID_SIZE; i++) {
                for (int j = 0; j < GRID_SIZE - 2; j++) {
                    if (grid[i][j] == grid[i][j + 1] && grid[i][j] == grid[i][j + 2]) {
                        toRemove[i][j] = true;
                        toRemove[i][j + 1] = true;
                        toRemove[i][j + 2] = true;
                        hasMatches = true;
                    }
                }
            }

            // 检查垂直匹配
            for (int j = 0; j < GRID_SIZE; j++) {
                for (int i = 0; i < GRID_SIZE - 2; i++) {
                    if (grid[i][j] == grid[i + 1][j] && grid[i][j] == grid[i + 2][j]) {
                        toRemove[i][j] = true;
                        toRemove[i + 1][j] = true;
                        toRemove[i + 2][j] = true;
                        hasMatches = true;
                    }
                }
            }

            // 移除匹配元素
            for (int i = 0; i < GRID_SIZE; i++) {
                for (int j = 0; j < GRID_SIZE; j++) {
                    if (toRemove[i][j]) {
                        grid[i][j] = -1;
                        currentScore++;
                    }
                }
            }

            // 填充空白位置
            for (int j = 0; j < GRID_SIZE; j++) {
                List<Integer> nonEmptyElements = new ArrayList<>();
                for (int i = GRID_SIZE - 1; i >= 0; i--) {
                    if (grid[i][j] != -1) {
                        nonEmptyElements.add(grid[i][j]);
                    }
                }
                for (int i = GRID_SIZE - 1; i >= 0; i--) {
                    if (nonEmptyElements.size() > 0) {
                        grid[i][j] = nonEmptyElements.remove(0);
                    } else {
                        grid[i][j] = random.nextInt(5);
                    }
                }
            }
        }
    }

    @Override
    protected void onDraw(Canvas canvas) {
        super.onDraw(canvas);
        for (int i = 0; i < GRID_SIZE; i++) {
            for (int j = 0; j < GRID_SIZE; j++) {
                int x = j * (ELEMENT_SIZE + MARGIN) + MARGIN;
                int y = i * (ELEMENT_SIZE + MARGIN) + MARGIN;
                if (grid[i][j] != -1) {
                    paint.setColor(getColorForElement(grid[i][j]));
                    canvas.drawRect(x, y, x + ELEMENT_SIZE, y + ELEMENT_SIZE, paint);
                }
            }
        }
        paint.setColor(Color.WHITE);
        paint.setTextSize(30);
        canvas.drawText("Steps: " + currentSteps + " / " + MAX_STEPS, 10, 30, paint);
        canvas.drawText("Score: " + currentScore + " / " + targetScore, 10, 70, paint);
        if (isGameOver) {
            if (currentScore >= targetScore) {
                canvas.drawText("You Win!", 10, 110, paint);
            } else {
                canvas.drawText("You Lose!", 10, 110, paint);
            }
        }
    }

    private int getColorForElement(int element) {
        switch (element) {
            case 0:
                return Color.RED;
            case 1:
                return Color.BLUE;
            case 2:
                return Color.GREEN;
            case 3:
                return Color.YELLOW;
            case 4:
                return Color.MAGENTA;
            default:
                return Color.BLACK;
        }
    }

    @Override
    public boolean onTouchEvent(MotionEvent event) {
        if (isGameOver) {
            return false;
        }
        int action = event.getAction();
        int x = (int) event.getX();
        int y = (int) event.getY();
        int gridX = x / (ELEMENT_SIZE + MARGIN);
        int gridY = y / (ELEMENT_SIZE + MARGIN);

        if (gridX < 0 || gridX >= GRID_SIZE || gridY < 0 || gridY >= GRID_SIZE) {
            return false;
        }

        switch (action) {
            case MotionEvent.ACTION_DOWN:
                startX = gridX;
                startY = gridY;
                isDragging = true;
                break;
            case MotionEvent.ACTION_MOVE:
                if (isDragging) {
                    endX = gridX;
                    endY = gridY;
                    if (isValidSwap(startX, startY, endX, endY)) {
                        swapElements(startX, startY, endX, endY);
                        checkAndRemoveMatches();
                        currentSteps++;
                        if (currentSteps >= MAX_STEPS) {
                            isGameOver = true;
                        }
                        if (currentScore >= targetScore) {
                            isGameOver = true;
                        }
                        invalidate();
                    }
                    isDragging = false;
                }
                break;
            case MotionEvent.ACTION_UP:
                isDragging = false;
                break;
        }
        return true;
    }

    private boolean isValidSwap(int x1, int y1, int x2, int y2) {
        return (Math.abs(x1 - x2) + Math.abs(y1 - y2) == 1);
    }

    private void swapElements(int x1, int y1, int x2, int y2) {
        int temp = grid[y1][x1];
        grid[y1][x1] = grid[y2][x2];
        grid[y2][x2] = temp;
    }

    public void resume() {
        // 可以添加恢复逻辑
    }

    public void pause() {
        // 可以添加暂停逻辑
    }
}

def quick_sort(arr):
    # 输入校验
    if not isinstance(arr, list):
        raise ValueError("输入必须是一个列表")

    for item in arr:
        if not isinstance(item, (int, float)):
            raise ValueError("列表中的所有元素必须是浮点数或整数")

    # 边界情况：空列表或单个元素直接返回
    if len(arr) <= 1:
        return arr

    # 选择基准值（这里选择第一个元素）
    pivot = arr[0]

    # 分区：将等于基准值的元素放在左侧，小于的放中间，大于的放右侧
    left = []
    middle = []
    right = []

    for num in arr:
        if num < pivot:
            left.append(num)
        elif num == pivot:
            middle.append(num)
        else:
            right.append(num)

    # 递归排序左右部分，并保持稳定性
    return quick_sort(left) + middle + quick_sort(right)

