# ==================== 辅助函数 ====================

def validate_password(password):
    """密码校验：至少6位，包含字母和数字"""
    if len(password) < 6:
        return False, "密码长度至少6位"
    if not re.search(r'[a-zA-Z]', password):
        return False, "密码必须包含字母"
    if not re.search(r'[0-9]', password):
        return False, "密码必须包含数字"
    return True, ""

def validate_isbn(isbn):
    """ISBN基本格式校验（13位数字或带连字符）"""
    isbn_clean = isbn.replace('-', '').replace(' ', '')
    if not isbn_clean.isdigit() or len(isbn_clean) not in (10, 13):
        return False, "ISBN格式无效，应为10或13位数字"
    return True, ""

def login_required(f):
    """登录验证装饰器"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({"error": "请先登录"}), 401
        return f(*args, **kwargs)
    return decorated_function

def admin_required(f):
    """管理员权限验证装饰器"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({"error": "请先登录"}), 401
        db = get_db()
        user = db.execute("SELECT role FROM users WHERE id=?", (session['user_id'],)).fetchone()
        if not user or user['role'] != 'admin':
            return jsonify({"error": "需要管理员权限"}), 403
        return f(*args, **kwargs)
    return decorated_function

def verified_user_required(f):
    """已验证用户权限装饰器（排除访客和未审核用户）"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({"error": "请先登录"}), 401
        db = get_db()
        user = db.execute("SELECT role, is_verified FROM users WHERE id=?", (session['user_id'],)).fetchone()
        if not user:
            return jsonify({"error": "用户不存在"}), 404
        if user['role'] == 'guest':
            return jsonify({"error": "访客无法执行此操作"}), 403
        if not user['is_verified']:
            return jsonify({"error": "账号未审核，功能受限"}), 403
        return f(*args, **kwargs)
    return decorated_function

