@app.route('/api/books', methods=['GET'])
def search_books():
    """搜索图书（支持按ISBN精确搜索）"""
    isbn = request.args.get('isbn', '').strip()

    db = get_db()
    if isbn:
        # 按ISBN搜索
        books = db.execute(
            "SELECT * FROM books WHERE isbn LIKE ?", (f'%{isbn}%',)
        ).fetchall()
