@app.route('/api/books/<int:book_id>', methods=['PUT'])
@admin_required
def update_book(book_id):
    """更新图书信息（管理员）"""
    data = request.get_json()
    if not data:
        return jsonify({"error": "请求数据为空"}), 400

    db = get_db()
    book = db.execute("SELECT * FROM books WHERE id=?", (book_id,)).fetchone()
    if not book:
        return jsonify({"error": "图书不存在"}), 404

    # 允许更新的字段
    update_fields = {}
    if 'title' in data and data['title'].strip():
        update_fields['title'] = data['title'].strip()
    if 'author' in data:
        update_fields['author'] = data['author'].strip()
    if 'publisher' in data:
        update_fields['publisher'] = data['publisher'].strip()
    if 'total_copies' in data:
        try:
            total = int(data['total_copies'])
            if total < 1:
                return jsonify({"error": "库存数量至少为1"}), 400
            # 计算可借数量变化
            diff = total - book['total_copies']
            new_available = book['available_copies'] + diff
            if new_available < 0:
                return jsonify({"error": "库存减少量超过当前可借数量"}), 400
            update_fields['total_copies'] = total
            update_fields['available_copies'] = new_available
        except (ValueError, TypeError):
            return jsonify({"error": "库存数量必须为整数"}), 400

    if not update_fields:
        return jsonify({"error": "没有需要更新的字段"}), 400

    # 构建更新SQL
    set_clause = ", ".join([f"{k}=?" for k in update_fields.keys()])
    values = list(update_fields.values())
    values.append(book_id)

    db.execute(f"UPDATE books SET {set_clause} WHERE id=?", values)
    db.commit()

    return jsonify({"message": "图书信息已更新"}), 200

