@app.route('/api/borrow', methods=['POST'])
@verified_user_required
def borrow_book():
    """借阅图书（仅限已审核用户）"""
    data = request.get_json()
    if not data:
        return jsonify({"error": "请求数据为空"}), 400

    book_id = data.get('book_id')
    borrow_days = data.get('borrow_days', 14)  # 默认14天

    # 校验借阅周期
    valid_periods = [7, 14, 30]
    if borrow_days not in valid_periods:
        return jsonify({"error": f"借阅周期无效，可选: {valid_periods}"}), 400

    if not book_id:
        return jsonify({"error": "请提供图书ID"}), 400

    db = get_db()

    # 检查图书是否存在且可借
    book = db.execute("SELECT * FROM books WHERE id=?", (book_id,)).fetchone()
    if not book:
        return jsonify({"error": "图书不存在"}), 404

    if book['available_copies'] <= 0:
        return jsonify({"error": "图书已全部借出"}), 409  # 异常处理：图书已借出

    # 检查用户是否有未归还的借阅（防止重复借阅同一本书）
    existing_borrow = db.execute(
        "SELECT id FROM borrow_records WHERE user_id=? AND book_id=? AND status='borrowed'",
        (session['user_id'], book_id)
    ).fetchone()
    if existing_borrow:
        return jsonify({"error": "您已借阅过此书，请先归还"}), 409

    # 创建借阅记录
    due_date = datetime.now() + timedelta(days=borrow_days)
    try:
        db.execute(
            "INSERT INTO borrow_records (user_id, book_id, due_date) VALUES (?, ?, ?)",
            (session['user_id'], book_id, due_date)
        )
        # 更新图书可借数量
        db.execute(
            "UPDATE books SET available_copies = available_copies - 1 WHERE id=?",
            (book_id,)
        )
        db.commit()
        return jsonify({
            "message": "借阅成功",
            "due_date": due_date.strftime('%Y-%m-%d %H:%M:%S')
        }), 201
    except Exception as e:
        db.rollback()
        return jsonify({"error": f"借阅失败: {str(e)}"}), 500

@app.route('/api/return', methods=['POST'])
@verified_user_required
def return_book():
    """归还图书"""
    data = request.get_json()
    if not data:
