/**
 * 稳定冒泡排序（升序），不修改原数组
 * @param {Array} arr - 待排序数组
 * @param {Function} [compareFn] - 可选比较函数，默认升序 (a, b) => a - b
 * @returns {Array} 排序后的新数组
 * @throws {TypeError} 如果输入不是数组或包含不可比较元素
 */
function bubbleSort(arr, compareFn) {
  // 输入校验
  if (!Array.isArray(arr)) {
    throw new TypeError('Input must be an array');
  }

  // 默认比较函数（升序）
  const defaultCompare = (a, b) => {
    if (a < b) return -1;
    if (a > b) return 1;
    return 0;
  };
  const compare = typeof compareFn === 'function' ? compareFn : defaultCompare;

  // 复制数组，避免修改原数组
  const result = arr.slice();

  const len = result.length;

  // 空数组或单元素数组直接返回
  if (len <= 1) {
    return result;
  }

  // 检查元素是否可比较（非 null/undefined 且能参与比较）
  for (let i = 0; i < len; i++) {
    const item = result[i];
    if (item === null || item === undefined) {
      throw new TypeError(`Element at index ${i} is ${item}, cannot compare`);
    }
    // 尝试比较第一个元素与自身，若抛出异常则说明不可比较
    try {
      compare(result[0], result[0]);
    } catch (e) {
      throw new TypeError('Elements are not comparable');
    }
  }

  // 冒泡排序（带提前终止标志）
  for (let i = 0; i < len - 1; i++) {
    let swapped = false;

    // 每轮比较次数递减（已排序尾部不再比较）
    for (let j = 0; j < len - 1 - i; j++) {
      // 稳定排序：仅当前一个大于后一个时才交换（相等不交换）
      if (compare(result[j], result[j + 1]) > 0) {
        [result[j], result[j + 1]] = [result[j + 1], result[j]];
        swapped = true;
      }
    }

    // 若本轮无交换，说明已有序，提前终止
    if (!swapped) {
      break;
    }
  }

  return result;
}

