function reverseString(input: string): string {
  // 输入校验：null 或 undefined 时返回 null
  if (input === null || input === undefined) {
    return null;
  }

  // 确保输入为字符串类型
  if (typeof input !== 'string') {
    throw new TypeError('Input must be a string');
  }

  // 边界条件：空字符串或单字符直接返回原值
  if (input.length <= 1) {
    return input;
  }

  // 将字符串转为数组（支持 Unicode 码点，如 emoji 组合）
  const arr = Array.from(input);
  let left = 0;
  let right = arr.length - 1;

  // 双指针原地反转
  while (left < right) {
    const temp = arr[left];
    arr[left] = arr[right];
    arr[right] = temp;
    left++;
    right--;
  }

  return arr.join('');
}

function capitalizeFirstLetterOfWords(str) {
  // 输入校验：如果输入不是字符串，返回 null
  if (typeof str !== 'string') {
    return null;
  }

  // 边界情况：空字符串直接返回空字符串
  if (str.length === 0) {
    return "";
  }

  let result = "";
  let i = 0;

  while (i < str.length) {
    // 检查当前字符是否为英文字母（a-z 或 A-Z）
    const isLetter = (ch) => {
      return (ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z');
    };

    if (isLetter(str[i])) {
      // 遇到单词首字母：大写（仅当它是小写时转换，大写保持不变）
      result += str[i].toUpperCase();
      i++;

      // 继续添加单词剩余字母，保持原样
      while (i < str.length && isLetter(str[i])) {
        result += str[i];
        i++;
      }
    } else {
      // 非字母字符直接保留
      result += str[i];
      i++;
    }
  }

  return result;
}

