import re

def parse_and_calculate(expression: str) -> float:
    """
    解析并计算表达式，按输入顺序依次计算（无优先级）。
    支持：加减乘除，十进制整数，负数。
    """
    # 去除所有空格
    expr = expression.replace(" ", "")
    if not expr:
        raise ValueError("输入为空")

    # 使用正则表达式分割数字和运算符
    # 匹配：可选负号 + 数字，或者运算符（+ - * /）
    tokens = re.findall(r'-?\d+|[+\-*/]', expr)
    if not tokens:
        raise ValueError("无法解析表达式")

    # 第一个必须是数字
    if not re.match(r'-?\d+', tokens[0]):
        raise ValueError(f"表达式必须以数字开头: {expression}")

    # 检查是否有连续运算符或结尾运算符
    # 简单校验：数字和运算符必须交替出现，且以数字结尾
    for i in range(len(tokens) - 1):
        if re.match(r'-?\d+', tokens[i]) and re.match(r'-?\d+', tokens[i+1]):
            raise ValueError(f"两个数字连续出现: {expression}")
        if re.match(r'[+\-*/]', tokens[i]) and re.match(r'[+\-*/]', tokens[i+1]):
            raise ValueError(f"两个运算符连续出现: {expression}")
    if re.match(r'[+\-*/]', tokens[-1]):
        raise ValueError(f"表达式不能以运算符结尾: {expression}")

    # 开始计算（按顺序）
    result = int(tokens[0])
    i = 1
    while i < len(tokens):
        operator = tokens[i]
        if i + 1 >= len(tokens):
            raise ValueError("表达式不完整")
        operand = int(tokens[i+1])

        if operator == '+':
            result += operand
        elif operator == '-':
            result -= operand
        elif operator == '*':
            result *= operand
        elif operator == '/':
            if operand == 0:
                raise ZeroDivisionError("除数不能为0")
            result /= operand
        else:
            raise ValueError(f"未知运算符: {operator}")

        i += 2

    return result

def main():
    print("简单计算器（按输入顺序计算，支持 + - * /，整数）")
    print("输入表达式，例如: 2+3*4")
    print("输入 'exit' 或 'quit' 退出程序")

    while True:
        try:
            user_input = input(">>> ").strip()
            if user_input.lower() in ('exit', 'quit'):
                print("再见！")
                break

            if not user_input:
                continue

            result = parse_and_calculate(user_input)
            # 保留两位小数，固定格式输出
            print(f"{result:.2f}")

        except (ValueError, ZeroDivisionError) as e:
            print(f"错误: {e}", file=sys.stderr)
            sys.exit(1)  # 直接报错并终止程序
        except Exception as e:
            print(f"未知错误: {e}", file=sys.stderr)
            sys.exit(1)

if __name__ == "__main__":
