def binary_search(arr, target):
    """
    在有序列表中使用二分查找算法查找目标值。

    参数:
        arr (list): 已排序的列表（升序），元素需支持比较操作。
        target: 要查找的目标值。

    返回:
        int: 如果找到目标值，返回其索引；否则返回 -1。

    异常:
        TypeError: 如果 arr 不是列表或 target 无法与列表元素比较。
        ValueError: 如果列表为空或未排序。
    """
    # 输入校验：确保 arr 是列表
    if not isinstance(arr, list):
        raise TypeError("输入 arr 必须是一个列表")

    # 输入校验：确保列表不为空
    if len(arr) == 0:
        raise ValueError("列表不能为空")

    # 输入校验：检查列表是否已排序（升序）
    for i in range(len(arr) - 1):
        try:
            if arr[i] > arr[i + 1]:
                raise ValueError("列表必须按升序排序")
        except TypeError:
            raise TypeError("列表元素类型不一致，无法比较")

    # 输入校验：确保 target 可以与列表元素比较（通过尝试比较第一个元素）
    try:
        _ = arr[0] < target
    except TypeError:
        raise TypeError(f"目标值 {target} 与列表元素类型不兼容")

    # 二分查找主逻辑
    left, right = 0, len(arr) - 1

    while left <= right:
        mid = left + (right - left) // 2  # 防止整数溢出
        try:
            if arr[mid] == target:
                return mid
            elif arr[mid] < target:
                left = mid + 1
            else:
                right = mid - 1
        except TypeError:
            # 理论上不会到达这里，因为前面已校验，但保留防御性代码
            raise TypeError("比较过程中出现类型错误")

    return -1

